import { rewriteShopAddressJumpLink } from '../shopAddressJumpLink';

describe('rewriteShopAddressJumpLink', () => {
  const H5_TEMPLATE = 'https://h5.ele.me/shop-map';

  describe('AC1: rewrites complexLayer ShopInfo schema to eleme://web', () => {
    it('extracts requestParams (eleStoreId/latitude/longitude) and embeds them into H5 query', () => {
      const requestParams = encodeURIComponent(
        JSON.stringify({ eleStoreId: 'E123', latitude: 30.1, longitude: 120.2 }),
      );
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      expect(out.startsWith('eleme://web?url=')).toBe(true);

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('https://h5.ele.me/shop-map');
      expect(decoded).toContain('eleStoreId=E123');
      expect(decoded).toContain('latitude=30.1');
      expect(decoded).toContain('longitude=120.2');
    });
  });

  describe('AC2: non-complexLayer schema is returned as-is', () => {
    it('returns lmagex link untouched', () => {
      const input = 'eleme://lmagex?scene_name=foo&eleStoreId=E1';
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC3: complexLayer with non-ShopInfo pageId is returned as-is', () => {
    it('returns Other pageId untouched', () => {
      const input = 'eleme://complexLayer?pageId=Other&requestParams=%7B%7D';
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC4: disableShopAddressH5=true forces fallback to original', () => {
    it('returns original ShopInfo schema untouched when disabled', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'true',
        }),
      ).toBe(input);
    });
  });

  describe('AC5: empty/missing shopAddressH5Url falls back to original', () => {
    it('returns original when H5 url is empty string', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: '',
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });

    it('returns original when H5 url is undefined', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: undefined,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC6: malformed input is returned as-is without throwing', () => {
    it('handles non-URL string', () => {
      expect(() =>
        rewriteShopAddressJumpLink('not-a-url', {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).not.toThrow();
    });

    it('handles empty string', () => {
      expect(
        rewriteShopAddressJumpLink('', {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe('');
    });

    it('handles null/undefined input gracefully', () => {
      // @ts-expect-error testing runtime safety
      expect(rewriteShopAddressJumpLink(null, { shopAddressH5Url: H5_TEMPLATE })).toBe('');
      // @ts-expect-error testing runtime safety
      expect(rewriteShopAddressJumpLink(undefined, { shopAddressH5Url: H5_TEMPLATE })).toBe('');
    });
  });

  describe('AC7: requestParams that is not valid JSON should not throw', () => {
    it('falls back to passing through other query params when requestParams is malformed', () => {
      const input = 'eleme://complexLayer?pageId=ShopInfo&requestParams=%7Bnot-json%7D&extra=keep';

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      expect(out.startsWith('eleme://web?url=')).toBe(true);
      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      // extra param is kept; eleStoreId / lat / lng are not present (because parse failed)
      expect(decoded).toContain('extra=keep');
      expect(decoded).not.toContain('eleStoreId=');
    });
  });

  describe('AC8: utParams is propagated as-is', () => {
    it('propagates utParams query string to H5 url', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const utParams = encodeURIComponent('{"a":1,"b":"x"}');
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}&utParams=${utParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('utParams=');
      // Inner JSON should survive a second decode
      const utValue = new URL(decoded).searchParams.get('utParams');
      expect(utValue).toBe('{"a":1,"b":"x"}');
    });
  });

  describe('AC bonus: H5 template that already has its own query string is merged correctly', () => {
    it('appends params with & when template already contains ?', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map?from=tb',
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('from=tb');
      expect(decoded).toContain('eleStoreId=E1');
      // No double ? in the URL
      const u = new URL(decoded);
      expect(u.searchParams.get('from')).toBe('tb');
      expect(u.searchParams.get('eleStoreId')).toBe('E1');
    });
  });
});

/**
 * Rewrites the legacy native "shop address landing page" jump link
 * (eleme://complexLayer?pageId=ShopInfo&...) into an H5 map page wrapped
 * by `eleme://web?url=...`.
 *
 * Falls back to the original link when:
 *   - the link is not a ShopInfo complexLayer schema
 *   - the H5 url template is empty / undefined
 *   - the rollback flag `disableShopAddressH5` is the literal string 'true'
 *   - the input cannot be parsed
 */

const SHOPINFO_PAGE_ID = 'ShopInfo';
const COMPLEX_LAYER_PREFIX = 'eleme://complexLayer';
const WEB_WRAPPER_PREFIX = 'eleme://web?url=';

export interface RewriteOptions {
  shopAddressH5Url?: string;
  disableShopAddressH5?: string | boolean;
}

interface ParsedComplexLayer {
  pageId: string | null;
  requestParams: string | null;
  utParams: string | null;
  otherParams: Array<[string, string]>;
}

const isDisabled = (flag: string | boolean | undefined): boolean => flag === 'true' || flag === true;

const parseComplexLayer = (input: string): ParsedComplexLayer | null => {
  // We do not rely on `new URL` because `eleme://` is a non-standard scheme
  // and some runtimes (notably miniapp / weex) may parse it inconsistently.
  const queryStart = input.indexOf('?');
  if (queryStart < 0) return { pageId: null, requestParams: null, utParams: null, otherParams: [] };

  const search = input.slice(queryStart + 1);
  const pairs = search.split('&').filter(Boolean);
  let pageId: string | null = null;
  let requestParams: string | null = null;
  let utParams: string | null = null;
  const otherParams: Array<[string, string]> = [];

  for (const pair of pairs) {
    const eq = pair.indexOf('=');
    const key = eq < 0 ? pair : pair.slice(0, eq);
    const rawValue = eq < 0 ? '' : pair.slice(eq + 1);
    let value: string;
    try {
      value = decodeURIComponent(rawValue);
    } catch {
      value = rawValue;
    }
    if (key === 'pageId') {
      pageId = value;
    } else if (key === 'requestParams') {
      requestParams = value;
    } else if (key === 'utParams') {
      utParams = value;
    } else {
      otherParams.push([key, value]);
    }
  }
  return { pageId, requestParams, utParams, otherParams };
};

const safeParseRequestParams = (raw: string | null): Record<string, unknown> | null => {
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object') return parsed as Record<string, unknown>;
    return null;
  } catch {
    return null;
  }
};

const appendQuery = (url: string, key: string, value: string): string => {
  const sep = url.includes('?') ? '&' : '?';
  return `${url}${sep}${encodeURIComponent(key)}=${encodeURIComponent(value)}`;
};

export const rewriteShopAddressJumpLink = (
  jumpLink: string | null | undefined,
  options: RewriteOptions = {},
): string => {
  // Defensive: empty / nullish inputs are returned as the empty string so that
  // downstream callers can still pass the value into navigate() without throwing.
  if (!jumpLink || typeof jumpLink !== 'string') return '';

  const { shopAddressH5Url, disableShopAddressH5 } = options;

  // Rollback / no-op fast paths.
  if (isDisabled(disableShopAddressH5)) return jumpLink;
  if (!shopAddressH5Url) return jumpLink;
  if (!jumpLink.startsWith(COMPLEX_LAYER_PREFIX)) return jumpLink;

  let parsed: ParsedComplexLayer | null;
  try {
    parsed = parseComplexLayer(jumpLink);
  } catch {
    return jumpLink;
  }
  if (!parsed) return jumpLink;
  if (parsed.pageId !== SHOPINFO_PAGE_ID) return jumpLink;

  // Build the H5 url, preserving the template's own query (if any).
  let h5Url = shopAddressH5Url;
  const requestObj = safeParseRequestParams(parsed.requestParams);
  if (requestObj) {
    for (const [k, v] of Object.entries(requestObj)) {
      if (v === undefined || v === null) continue;
      h5Url = appendQuery(h5Url, k, String(v));
    }
  }
  if (parsed.utParams) {
    h5Url = appendQuery(h5Url, 'utParams', parsed.utParams);
  }
  for (const [k, v] of parsed.otherParams) {
    // Avoid clobbering query keys we already wrote (eleStoreId etc.) — they win.
    h5Url = appendQuery(h5Url, k, v);
  }

  return `${WEB_WRAPPER_PREFIX}${encodeURIComponent(h5Url)}`;
};

export default rewriteShopAddressJumpLink;

import { renderHook, act } from '@testing-library/react-hooks';
import { useShopAddressNavigate } from '../useShopAddressNavigate';

// $ele() is a global declared in typings.d.ts; in tests we replace it.
const mockNavigate = jest.fn();

beforeAll(() => {
  // @ts-expect-error injecting test global
  global.$ele = jest.fn(() => ({ navigate: mockNavigate }));
});

beforeEach(() => {
  mockNavigate.mockReset();
  // Reset downgraded configuration to a clean slate per test.
  delete (window as any).__downgradedConfiguration;
});

const setConfig = (cfg: Record<string, unknown>) => {
  (window as any).__downgradedConfiguration = cfg;
};

describe('useShopAddressNavigate', () => {
  describe('AC1: rewrites and navigates when H5 url is configured and link is ShopInfo', () => {
    it('calls $ele().navigate exactly once with the eleme://web url', () => {
      setConfig({
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledTimes(1);
      const called = mockNavigate.mock.calls[0][0] as { url: string };
      expect(called.url.startsWith('eleme://web?url=')).toBe(true);
    });
  });

  describe('AC2: passes original link through when H5 url is missing', () => {
    it('calls navigate with the unchanged link', () => {
      // No __downgradedConfiguration at all.
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledTimes(1);
      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC3: passes through non-ShopInfo links untouched', () => {
    it('does not rewrite lmagex schema even when H5 url is configured', () => {
      setConfig({ shopAddressH5Url: 'https://h5.ele.me/shop-map' });
      const link = 'eleme://lmagex?scene_name=foo';

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC4: rollback flag forces fallback to original link', () => {
    it('does not rewrite when disableShopAddressH5=true even if H5 url is configured', () => {
      setConfig({
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'true',
      });
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC bonus: empty / nullish input does not crash and does not call navigate', () => {
    it('skips navigate for empty string', () => {
      setConfig({ shopAddressH5Url: 'https://h5.ele.me/shop-map' });

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress('');
      });

      expect(mockNavigate).not.toHaveBeenCalled();
    });
  });
});

import { useCallback } from 'react';
import { rewriteShopAddressJumpLink } from '@/common/utils/shopAddressJumpLink';

/**
 * Hook that wraps `$ele().navigate({ url })` with the shop-address jump-link
 * rewrite logic. Components that previously called `$ele().navigate({ url: jumpLink })`
 * directly to open the legacy `eleme://complexLayer?pageId=ShopInfo&...` page
 * should switch to `navigateToShopAddress(jumpLink)` so that we can route the
 * user to the new H5 map page when configured.
 *
 * Reads two fields from `window.__downgradedConfiguration`:
 *   - shopAddressH5Url:        H5 map page URL template (no rewrite when empty)
 *   - disableShopAddressH5:    'true' for one-click rollback
 */
export const useShopAddressNavigate = () => {
  const navigateToShopAddress = useCallback((jumpLink: string | null | undefined) => {
    if (!jumpLink) return;

    const config = (typeof window !== 'undefined'
      ? (window as Window & {
          __downgradedConfiguration?: {
            shopAddressH5Url?: string;
            disableShopAddressH5?: string;
            [key: string]: unknown;
          };
        }).__downgradedConfiguration
      : undefined) ?? {};

    const finalUrl = rewriteShopAddressJumpLink(jumpLink, {
      shopAddressH5Url: config.shopAddressH5Url,
      disableShopAddressH5: config.disableShopAddressH5,
    });

    try {
      $ele().navigate({ url: finalUrl });
    } catch (err) {
      // Fallback: if rewrite produced something the navigator dislikes, retry
      // with the raw link so the user is never stranded.
      // eslint-disable-next-line no-console
      console.error('[useShopAddressNavigate] navigate failed, falling back to raw link', err);
      try {
        $ele().navigate({ url: jumpLink });
      } catch (innerErr) {
        // eslint-disable-next-line no-console
        console.error('[useShopAddressNavigate] fallback navigate also failed', innerErr);
      }
    }
  }, []);

  return { navigateToShopAddress };
};

export default useShopAddressNavigate;

