const SHOPINFO_PAGE_ID = 'ShopInfo';
const COMPLEX_LAYER_PREFIX = 'eleme://complexLayer';
const WEB_WRAPPER_PREFIX = 'eleme://web?url=';

/**
 * Default allow-list of host suffixes for the H5 map page.
 * Anything that does not match is rejected to defend against:
 *   - configuration-source poisoning (e.g. devtools / XSS write to
 *     `window.__downgradedConfiguration.shopAddressH5Url`)
 *   - dangerous URL schemes such as `javascript:`, `data:`, `file:`
 *   - open-redirect to phishing domains
 */
const DEFAULT_ALLOWED_HOST_SUFFIXES = ['.ele.me', '.alibaba-inc.com', '.taobao.com', '.tmall.com'];

export interface RewriteOptions {
  shopAddressH5Url?: string;
  disableShopAddressH5?: string | boolean;
  /** Override the default host allow-list. Pass an empty array to disable
   * the safety check (NOT recommended outside tests). */
  allowedHostSuffixes?: string[];
}

const isAllowedH5Url = (url: unknown, allowedSuffixes: string[]): url is string => {
  if (typeof url !== 'string' || url.length === 0) return false;
  // Must be HTTPS — blocks javascript:, data:, file:, http:, eleme:, etc.
  if (!url.startsWith('https://')) return false;
  // Empty allow-list disables the host check (test override only).
  if (allowedSuffixes.length === 0) return true;
  let host: string;
  try {
    host = new URL(url).hostname.toLowerCase();
  } catch {
    return false;
  }
  if (!host) return false;
  return allowedSuffixes.some(
    (suffix) => host === suffix.replace(/^\./, '') || host.endsWith(suffix.toLowerCase()),
  );
};

