export const useShopAddressNavigate = () => {
  // Empty deps array is intentional: the configuration is read at *call*
  // time inside the callback, not at render time, so the closure cannot
  // become stale. Do NOT lift the config read above this line, or you
  // will miss runtime updates of `__downgradedConfiguration`.
  const navigateToShopAddress = useCallback((jumpLink: string | null | undefined) => {
    if (!jumpLink) return;

    const config = (typeof window !== 'undefined'
      ? (window as Window & {
          __downgradedConfiguration?: {
            shopAddressH5Url?: string;
            disableShopAddressH5?: string;
            [key: string]: unknown;
          };
        }).__downgradedConfiguration
      : undefined) ?? {};

    // Runtime-typed extraction: configuration is global writable state, so
    // even though TypeScript believes the fields are strings we still verify
    // at runtime to defend against numbers / objects / null injected by
    // unrelated code paths.
    const rawH5Url = config.shopAddressH5Url;
    const shopAddressH5Url = typeof rawH5Url === 'string' ? rawH5Url : undefined;
    const rawDisable = config.disableShopAddressH5;
    const disableShopAddressH5 =
      typeof rawDisable === 'string' || typeof rawDisable === 'boolean' ? rawDisable : undefined;

    const finalUrl = rewriteShopAddressJumpLink(jumpLink, {
      shopAddressH5Url,
      disableShopAddressH5,
    });

