import React, { useCallback, useState } from 'react';
import { Popup } from '@ali/acom-unify-mobile-components';
import Swiper from '@/components/swiper';
import styles from './index.module.css';
import LTrackerView from '@ali/alsc-conch-ltracker-plugin/esm/LTrackerView';
import { spmCD, spmClick, spmExposure } from '../../utils';
import { rpxToPxV2 } from '@/common/utils/shared';
import { useShopAddressNavigate } from '@/hooks/useShopAddressNavigate';

interface ServiceSubItem {
  type: string;
  title: string;
  text: string;
  color?: string;
  icon?: string;
  rightIcon?: string;
  iconRatio?: number;
  businessType?: string;
  userTrack?: {
    control_name?: string;
    spm_c?: string;
    bizParams?: Record<string, any>;
    spm_d?: string | number;
    exposure_name?: string;
  };
  alertInfo?: {
    noticeImage: string;
    imageRatio: number | string;
    closeUserTrack?: Record<string, any>;
    userTrack?: Record<string, any>;
  };
}

interface ServiceItem {
  type: string;
  title: string;
  text: string;
  subList?: ServiceSubItem[];
  alertInfo?: {
    noticeImage: string;
    imageRatio: number;
    closeUserTrack?: {
      close_control_name?: string;
      control_name?: string;
      spm_c?: string;
      bizParams?: Record<string, unknown>;
      spm_d?: string;
      exposure_name?: string;
    };
    userTrack?: {
      control_name?: string;
      spm_c?: string;
      bizParams?: Record<string, unknown>;
      spm_d?: string;
      exposure_name?: string;
    };
  };
  color?: string;
  icon?: string;
  rightIcon?: string;
  iconRatio?: number;
  userTrack?: {
    close_control_name?: string;
    control_name?: string;
    spm_c?: string;
    bizParams?: Record<string, any>;
    spm_d?: string;
    exposure_name?: string;
  };
  jumpLink?: string;
}

interface StoreServiceListProps {
  serviceList?: ServiceItem[];
  isSkeleton?: boolean;
  onServiceClick?: () => void;
}

const ICON_SIZE = 22;

const StoreServiceList: React.FC<StoreServiceListProps> = ({
  serviceList = [],
  isSkeleton,
  onServiceClick,
}) => {
  const [alertVisible, setAlertVisible] = useState(false);
  const { navigateToShopAddress } = useShopAddressNavigate();
  const [currentAlertData, setCurrentAlertData] = useState<{
    alertInfo: {
      noticeImage: string;
      imageRatio: number;
      closeUserTrack?: {
        close_control_name?: string;
        control_name?: string;
        spm_c?: string;
        bizParams?: Record<string, unknown>;
        spm_d?: string;
        exposure_name?: string;
      };
      userTrack?: {
        control_name?: string;
        spm_c?: string;
        bizParams?: Record<string, unknown>;
        spm_d?: string;
        exposure_name?: string;
      };
    };
    text: string;
    title: string;
    color: string;
  } | null>(null);

  // 弹窗关闭方法
  const handleCloseAlert = () => {
    if (currentAlertData?.alertInfo?.closeUserTrack) {
      // 发送关闭埋点
      spmClick(currentAlertData.alertInfo.closeUserTrack);
    }
    setAlertVisible(false);
  };

  // 渲染 value 部分（用于轮播）
  const renderValueContent = useCallback(
    (itemData: ServiceSubItem | ServiceItem, isSubList = false) => {
      const color = itemData.color ?? '#11192D';
      const leftIcon = itemData.icon;
      const rightIcon = itemData.rightIcon;
      const iconRatio = itemData.iconRatio ?? 1;

      return (
        <span className={isSubList ? styles.valueSublistRow : styles.valueRow}>
          {leftIcon && (
            <span className={styles.valueIcon}>
              <img
                alt=""
                src={leftIcon}
                style={{ height: rpxToPxV2(ICON_SIZE), width: rpxToPxV2(ICON_SIZE * iconRatio) }}
              />
            </span>
          )}
          <span
            className={`${styles.value} ${
              (itemData.type === 'rate' && parseFloat(itemData.text) > 0) ||
              itemData.type === 'monthSale'
                ? styles.highlight
                : ''
            }`}
            style={{
              color: isSkeleton ? '#F3F6F8' : color,
              backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent',
            }}
          >
            {itemData.text}
          </span>
          {rightIcon && (
            <span className={styles.valueArrow}>
              <img alt="" src={rightIcon} style={{ width: rpxToPxV2(20), height: rpxToPxV2(20) }} />
            </span>
          )}
        </span>
      );
    },
    [isSkeleton],
  );

  if (!serviceList.length) return null;

  return (
    <div
      className={styles.serviceList}
      onClick={onServiceClick}
      role="button"
      aria-label={`店铺服务信息：${serviceList.map((s) => `${s.title}${s.text}`).join('，')}`}
      tabIndex={0}
    >
      {serviceList.map((service, index) => {
        const hasAlert = Boolean(service.alertInfo) || Boolean(service.jumpLink);
        const jumpLink = service.jumpLink;
        const hasSubList = service.subList && service.subList.length > 0;

        const handleItemClick = (
          e: React.MouseEvent<HTMLDivElement>,
          clickedItem?: ServiceSubItem,
        ) => {
          const targetItem = clickedItem ?? service;
          const targetJumpLink = (clickedItem as any)?.jumpLink ?? jumpLink;
          const targetAlertInfo = clickedItem?.alertInfo ?? service.alertInfo;

          // 发送点击埋点 - 优先使用 clickedItem 的 userTrack，否则使用 service 的 userTrack
          const targetUserTrack = clickedItem?.userTrack ?? service.userTrack;
          if (targetUserTrack) {
            spmClick(targetUserTrack);
          }

          // 有跳转链接优先走跳转链接跳转
          if (targetJumpLink && targetJumpLink.length > 0) {
            e?.stopPropagation?.();
            // Routed through useShopAddressNavigate so the legacy
            // `eleme://complexLayer?pageId=ShopInfo&...` link can be
            // rewritten to the new H5 map page when configured. Other
            // jump links are passed through unchanged.
            navigateToShopAddress(targetJumpLink);
            return;
          }

          if (!targetAlertInfo) return;
          e.stopPropagation();

          // 设置弹窗数据并显示
          setCurrentAlertData({
            alertInfo: {
              noticeImage: targetAlertInfo.noticeImage ?? '',
              imageRatio:
                typeof targetAlertInfo.imageRatio === 'string'
                  ? parseFloat(targetAlertInfo.imageRatio)
                  : (targetAlertInfo.imageRatio ?? 1),
              closeUserTrack: targetAlertInfo.closeUserTrack ?? {},
              userTrack: targetAlertInfo.userTrack ?? {},
            },
            text: targetItem.text ?? '',
            title: targetItem.title ?? '',
            color: targetItem.color ?? '#FF6200',
          });
          setAlertVisible(true);
        };

        return (
          <React.Fragment key={`${service.type}-${index}`}>
            {index > 0 && <div className={styles.separator} />}
            {hasSubList ? (
              <div className={styles.serviceItem}>
                <span className={styles.content}>
                  <span
                    className={styles.title}
                    style={{
                      color: isSkeleton ? '#F3F6F8' : '#7c889c',
                      backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent',
                    }}
                  >
                    {service.title}
                  </span>
                  <div className={styles.valueSwiperWrapper}>
                    {/* 透明占位元素，用于撑开宽度 */}
                    <div
                      className={styles.valuePlaceholder}
                      aria-hidden="true"
                      style={{
                        pointerEvents: 'none',
                        display: 'flex',
                        flexDirection: 'column',
                        height: '30rpx',
                        width: 'fit-content',
                      }}
                    >
                      {service.subList!.map((subItem, subIndex) => (
                        <span key={subIndex} className={styles.placeholderItem}>
                          {renderValueContent(subItem, true)}
                        </span>
                      ))}
                    </div>
                    {/* 实际的轮播容器 */}
                    <div className={styles.valueSwiper}>
                      <Swiper
                        className={styles.valueSwiperContainer}
                        navigation={false}
                        pagination={false}
                        swipeable={false}
                        interval={3000}
                        autoplay={true}
                        loop
                        vertical
                        dataSource={service.subList}
                        renderItem={({ item: subItem }) => {
                          const subHasAlert =
                            Boolean(subItem.alertInfo) || Boolean((subItem as any).jumpLink);
                          const handleSubItemClick = (e: React.MouseEvent<HTMLDivElement>) => {
                            handleItemClick(e, subItem);
                          };
                          return (
                            <LTrackerView
                              auto-spmcd={spmCD(subItem.userTrack ?? {})}
                              getLTrackerDataList={() => subItem.userTrack?.bizParams ?? {}}
                              className={styles.valueSwiperItem}
                              onClick={subHasAlert ? handleSubItemClick : undefined}
                            >
                              {renderValueContent(subItem, true)}
                            </LTrackerView>
                          );
                        }}
                      />
                    </div>
                  </div>
                </span>
              </div>
            ) : (
              <LTrackerView
                auto-spmcd={spmCD(service.userTrack ?? {})}
                getLTrackerDataList={() => service.userTrack?.bizParams ?? {}}
                className={styles.serviceItem}
                onClick={hasAlert ? handleItemClick : undefined}
              >
                <span className={styles.content}>
                  <span
                    className={styles.title}
                    style={{
                      color: isSkeleton ? '#F3F6F8' : '#7c889c',
                      backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent',
                    }}
                  >
                    {service.title}
                  </span>
                  {renderValueContent(service)}
                </span>
              </LTrackerView>
            )}
          </React.Fragment>
        );
      })}

      {/* 商家特色弹窗 */}
      {currentAlertData && (
        <Popup
          visible={alertVisible}
          round
          title={currentAlertData.title ?? ''}
          titleAlign="center"
          bodyClassName={styles.popupWrapper}
          maskClassName={styles.popupMask}
          onClose={handleCloseAlert}
          popHeight={0.8}
          showClose={false}
          bodyStyle={{
            // '--confirm-theme-color': theme.themeColor,
            borderTopLeftRadius: rpxToPxV2(12),
            borderTopRightRadius: rpxToPxV2(12),
          }}
          afterShow={() => {
            if (currentAlertData?.alertInfo?.userTrack) {
              spmExposure(currentAlertData.alertInfo.userTrack);
            }
          }}
        >
          <div className={styles.popupContent}>
            <div
              className={styles.imageContainer}
              style={{
                paddingTop: currentAlertData?.alertInfo?.imageRatio
                  ? `${100 / currentAlertData.alertInfo.imageRatio}%`
                  : '100%',
              }}
            >
              <img
                src={currentAlertData.alertInfo?.noticeImage ?? ''}
                alt={currentAlertData.text ?? ''}
                className={styles.noticeImage}
              />
            </div>
            <div className={styles.buttonContainer}>
              <button
                className={styles.customKnowButton}
                onClick={handleCloseAlert}
                style={{
                  backgroundColor: '#FF6200',
                }}
              >
                知道了
              </button>
            </div>
            <div
              style={{
                position: 'absolute',
                top: rpxToPxV2(20),
                right: rpxToPxV2(20),
                width: rpxToPxV2(56),
                height: rpxToPxV2(56),
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                backgroundColor: '#F3F6F8',
                borderRadius: rpxToPxV2(8),
                zIndex: 1000,
              }}
              onClick={handleCloseAlert}
              role="button"
              aria-label="关闭"
            >
              <img
                src="https://gw.alicdn.com/imgextra/i2/O1CN01OklgmO1J9BDe97WVt_!!6000000000985-2-tps-64-64.png"
                alt="close"
                style={{
                  width: rpxToPxV2(32),
                  height: rpxToPxV2(32),
                  objectFit: 'cover',
                }}
              />
            </div>
          </div>
        </Popup>
      )}
    </div>
  );
};

