    storeBusiness?: {
      bookTitle?: string[];
    };
    storeHeadLogoDTO?: {
      wideIcon?: string;
      wideIconRatio?: number;
      text?: string;
      color?: string;
      background?: {
        rgbFrom?: string;
        rgbTo?: string;
      };
      userTrack?: {
        bizParams?: Record<string, unknown>;
        control_name?: string;
        exposure_name?: string;
        spm_c?: string;
        spm_d?: number;
      };
    };
  };
  themeColor?: string;
  onTitleClick?: () => void;
  isSkeleton?: boolean;
}

const StoreTitleRow: React.FC<StoreTitleRowProps> = ({
  storeInfo,
  themeColor = '#FF6200',
  onTitleClick,
  isSkeleton,
}) => {
  const nameRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const dispatch = useDispatch();
  const [showMask, setShowMask] = useState(false);
  const hasExposedTextTagRef = useRef(false);
  const { navigateToShopAddress } = useShopAddressNavigate();

  // 处理店铺名称点击
  const handleTitleClick = () => {
    if (onTitleClick) {
      onTitleClick();
    } else if (storeInfo.jumpLink) {
      // Routed through useShopAddressNavigate so the legacy
      // `eleme://complexLayer?pageId=ShopInfo&...` link can be
      // rewritten to the new H5 map page when configured.
      navigateToShopAddress(storeInfo.jumpLink);
    }
  };

  // 处理小蓝心点击
  const handleBlueTagClick = () => {
    if (storeInfo.storeBlueTag?.scheme) {
      $ele().navigate({ url: storeInfo.storeBlueTag.scheme });
    }
  };

  // 处理切换按钮点击
  const handleSwitchClick = () => {
    if (storeInfo.fillStoreId) {
      const url = `eleme://lmagex?scene_name=wm_shop_select&is_mist_page=1&eleStoreId=${
        storeInfo.fillStoreId
      }&brandIds=${encodeURIComponent(JSON.stringify([storeInfo.brandId]))}`;
      $ele().navigate({ url });
    }
  };

  // 处理预定按钮点击
  const _handleBookingClick = () => {
    dispatch({ type: 'page/showBookingPanel', payload: true });
  };

  // 预定按钮文本
  const bookTitles = storeInfo.storeBusiness?.bookTitle;
  const hasBookTitle = bookTitles && bookTitles.length > 0;

  // // 判断是否需要显示遮罩
  useEffect(() => {
    const checkOverflow = async () => {
      const scroll = scrollRef.current;
      const name = nameRef.current;
      if (!scroll || !name) return;
      try {
        const container = await getBoundingClientRectAsync(scroll);
        const containerWidth = container?.width || 0;
        if (containerWidth < 1) return;
        const text = await getBoundingClientRectAsync(name);
        const textWidth = text?.width || 0;

        if (containerWidth < textWidth) {
          setShowMask(true);
        }
      } catch (error) {}
    };
    if (storeInfo?.name?.length > 0 && scrollRef.current && nameRef.current) {
      requestAnimationFrame(() => {
        checkOverflow();
      });
    }

    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [storeInfo.name, storeInfo.storeBlueTag, hasBookTitle]);

  // 判断是否显示横版Logo
  const hasWideLogo = storeInfo.storeHeadLogoDTO?.wideIcon;
  // 计算横版Logo的宽度：高度固定36rpx，宽度根据比例计算
  const wideLogoHeight = 36; // rpx
  const wideLogoRatio = storeInfo.storeHeadLogoDTO?.wideIconRatio ?? 1;
  const wideLogoWidth = wideLogoHeight * wideLogoRatio; // rpx

  // 判断是否显示可堂食标签：只有在没有横版Logo且有text时才显示
  const showTextTag = !hasWideLogo && storeInfo.storeHeadLogoDTO?.text;
  const textTagColor = storeInfo.storeHeadLogoDTO?.color ?? '#0FAD50';
  const textTagBgColor = storeInfo.storeHeadLogoDTO?.background?.rgbFrom ?? '#EEFAE7';
  const textTagUserTrack = storeInfo.storeHeadLogoDTO?.userTrack;

  // 处理可堂食标签点击
  const handleTextTagClick = () => {
    if (textTagUserTrack?.control_name && textTagUserTrack?.spm_c) {
      try {
        $ele().ltracker.click(`${textTagUserTrack.spm_c}.${textTagUserTrack.spm_d ?? '1'}`, {
          ...(textTagUserTrack.bizParams ?? {}),
        });
      } catch (error) {
        console.error('可堂食标签点击埋点失败:', error);
      }
    }
  };

  // 可堂食标签曝光埋点
  useEffect(() => {
    if (showTextTag && textTagUserTrack && !hasExposedTextTagRef.current) {
      if (textTagUserTrack.exposure_name && textTagUserTrack.spm_c) {
        try {
          $ele().ltracker.expo(`${textTagUserTrack.spm_c}.${textTagUserTrack.spm_d ?? '1'}`, {
            ...(textTagUserTrack.bizParams ?? {}),
          });
          hasExposedTextTagRef.current = true;
        } catch (error) {
          console.error('可堂食标签曝光埋点失败:', error);
        }
      }
    }

    // 标签隐藏时重置曝光标记
    if (!showTextTag) {
      hasExposedTextTagRef.current = false;
    }
  }, [showTextTag, textTagUserTrack]);

  return (
    <div className={styles.titleRow} role="button" aria-label={`店铺标题：${storeInfo.name}`}>
      <div className={styles.nameSection}>
        {/* 横版Logo */}
        {hasWideLogo && (
          <img
            src={
              isSkeleton
                ? ''
                : $ele().utils.hashToUrl({
                    hash: hasWideLogo ?? '',
                    width: wideLogoWidth * 2, // 2倍图
                    height: wideLogoHeight * 2, // 2倍图
                  })
            }
            onClick={handleTitleClick}
            style={{
              width: rpxToPxV2(wideLogoWidth),
              height: rpxToPxV2(wideLogoHeight),
              backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent',
              marginRight: rpxToPxV2(8),
              flexShrink: 0,
            }}
            role="none"
          />
        )}
        {/* 可堂食文字标签 */}
        {showTextTag && (
          <div
            className={styles.textTag}
            style={{
              backgroundColor: textTagBgColor,
              color: textTagColor,
              cursor: 'pointer',
            }}
            onClick={handleTextTagClick}
            role="button"
            aria-label={`${storeInfo.storeHeadLogoDTO?.text}标签`}
            tabIndex={0}
          >
            {storeInfo.storeHeadLogoDTO?.text}
          </div>
        )}
        <div className={styles.nameWrap}>
          <div
            className={styles.nameScroll}
            ref={scrollRef}
            style={{ backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent' }}
            aria-hidden="true"
            role="none"
          >
            {storeInfo.name && (
              <div
                id="et-page-stability-title" // 用于页面稳定性检测，改动id请同步修改usePageStability代码
                className={styles.name}
                ref={nameRef}
                onClick={handleTitleClick}
                style={{ cursor: storeInfo.jumpLink || onTitleClick ? 'pointer' : 'default' }}
                role={'button'}
                aria-label={storeInfo.name}
              >
                {storeInfo.name}
              </div>
            )}
          </div>
          {/* 遮罩：只有内容溢出时显示 */}
          {showMask && (
            <img
              className={styles.nameMask}
              src="https://gw.alicdn.com/imgextra/i2/O1CN01Pcr1rS1GL8bspap1e_!!6000000000605-2-tps-48-124.png"
              alt="mask"
              aria-hidden={true}
              role={'none'}
            />
          )}
        </div>
        {/* 小蓝心标签 */}
        {storeInfo.storeBlueTag?.storeBlueStyle === 1 && storeInfo.storeBlueTag?.image && (
          <img
            className={styles.blueTag}
            src={$ele().utils.hashToUrl({ hash: storeInfo.storeBlueTag.image })}
            alt="blue tag"
            onClick={handleBlueTagClick}
            role={'button'}
            aria-label={'小蓝心标签'}
            tabIndex={0}
          />
        )}
        {/* 切换按钮 */}
        {storeInfo.fillStoreId && (
          <div
            className={styles.switchBtn}
            onClick={handleSwitchClick}
            role={'button'}
            aria-label={'切换店铺'}
            tabIndex={0}
          >
            切换
          </div>
        )}
        {/* 预定按钮 */}
        {hasBookTitle &&
          (bookTitles.length === 1 ? (
            <div
              className={styles.bookBtn}
              onClick={_handleBookingClick}
              style={{ borderColor: `${themeColor}`, color: `${themeColor}`, marginLeft: 8 }}
              role={'button'}
              aria-label={bookTitles[0]}
              tabIndex={0}
            >
              {bookTitles[0]}
            </div>
          ) : (
            <div
              className={styles.bookContent}
              onClick={_handleBookingClick}
              role="button"
              aria-label={`预定服务：${bookTitles.join('、')}`}
              tabIndex={0}
            >
              <Swiper
                // scroll-direction="vertical"
                // infinite="true"
                // interval={3000}
                // duration={1000}
                // auto-play="true"
                // // scrollable="false"
                // style={{ height: '20px', width: '48px' }}
                // onClick={_handleBookingClick}
                // aria-hidden="true"
                // role="none"
                vertical={true}
                autoplay={true}
                swipeable={false}
                navigation={false}
                pagination={false}
                speed={1000}
                interval={3000}
                loop={true}
                onClick={_handleBookingClick}
              >
                {bookTitles.map((title) => (
                  <div
                    key={title}
                    className={styles.bookBtn}
                    style={{ borderColor: `${themeColor}`, color: `${themeColor}` }}
                    role={'button'}
                    aria-label={title}
                    aria-hidden="true"
                  >
                    {title}
                  </div>
                ))}
              </Swiper>
            </div>
          ))}
      </div>
    </div>
  );
};

export default StoreTitleRow;

