import { rewriteShopAddressJumpLink } from '../shopAddressJumpLink';

describe('rewriteShopAddressJumpLink', () => {
  const H5_TEMPLATE = 'https://h5.ele.me/shop-map';

  describe('AC1: rewrites complexLayer ShopInfo schema to eleme://web', () => {
    it('extracts requestParams (eleStoreId/latitude/longitude) and embeds them into H5 query', () => {
      const requestParams = encodeURIComponent(
        JSON.stringify({ eleStoreId: 'E123', latitude: 30.1, longitude: 120.2 }),
      );
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      expect(out.startsWith('eleme://web?url=')).toBe(true);

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('https://h5.ele.me/shop-map');
      expect(decoded).toContain('eleStoreId=E123');
      expect(decoded).toContain('latitude=30.1');
      expect(decoded).toContain('longitude=120.2');
    });
  });

  describe('AC2: non-complexLayer schema is returned as-is', () => {
    it('returns lmagex link untouched', () => {
      const input = 'eleme://lmagex?scene_name=foo&eleStoreId=E1';
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC3: complexLayer with non-ShopInfo pageId is returned as-is', () => {
    it('returns Other pageId untouched', () => {
      const input = 'eleme://complexLayer?pageId=Other&requestParams=%7B%7D';
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC4: disableShopAddressH5=true forces fallback to original', () => {
    it('returns original ShopInfo schema untouched when disabled', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'true',
        }),
      ).toBe(input);
    });
  });

  describe('AC5: empty/missing shopAddressH5Url falls back to original', () => {
    it('returns original when H5 url is empty string', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: '',
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });

    it('returns original when H5 url is undefined', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;
      expect(
        rewriteShopAddressJumpLink(input, {
          shopAddressH5Url: undefined,
          disableShopAddressH5: 'false',
        }),
      ).toBe(input);
    });
  });

  describe('AC6: malformed input is returned as-is without throwing', () => {
    it('handles non-URL string', () => {
      expect(() =>
        rewriteShopAddressJumpLink('not-a-url', {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).not.toThrow();
    });

    it('handles empty string', () => {
      expect(
        rewriteShopAddressJumpLink('', {
          shopAddressH5Url: H5_TEMPLATE,
          disableShopAddressH5: 'false',
        }),
      ).toBe('');
    });

    it('handles null/undefined input gracefully', () => {
      expect(rewriteShopAddressJumpLink(null, { shopAddressH5Url: H5_TEMPLATE })).toBe('');
      expect(rewriteShopAddressJumpLink(undefined, { shopAddressH5Url: H5_TEMPLATE })).toBe('');
    });
  });

  describe('AC7: requestParams that is not valid JSON should not throw', () => {
    it('falls back to passing through other query params when requestParams is malformed', () => {
      const input = 'eleme://complexLayer?pageId=ShopInfo&requestParams=%7Bnot-json%7D&extra=keep';

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      expect(out.startsWith('eleme://web?url=')).toBe(true);
      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      // extra param is kept; eleStoreId / lat / lng are not present (because parse failed)
      expect(decoded).toContain('extra=keep');
      expect(decoded).not.toContain('eleStoreId=');
    });
  });

  describe('AC8: utParams is propagated as-is', () => {
    it('propagates utParams query string to H5 url', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const utParams = encodeURIComponent('{"a":1,"b":"x"}');
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}&utParams=${utParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: H5_TEMPLATE,
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('utParams=');
      // Inner JSON should survive a second decode
      const utValue = new URL(decoded).searchParams.get('utParams');
      expect(utValue).toBe('{"a":1,"b":"x"}');
    });
  });

  describe('AC bonus: H5 template that already has its own query string is merged correctly', () => {
    it('appends params with & when template already contains ?', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map?from=tb',
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      expect(decoded).toContain('from=tb');
      expect(decoded).toContain('eleStoreId=E1');
      // No double ? in the URL
      const u = new URL(decoded);
      expect(u.searchParams.get('from')).toBe('tb');
      expect(u.searchParams.get('eleStoreId')).toBe('E1');
    });
  });

  describe('Security: H5 url scheme allow-list', () => {
    const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
    const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

    it.each([
      ['javascript:alert(1)'],
      ['data:text/html,<script>1</script>'],
      ['file:///etc/passwd'],
      ['http://h5.ele.me/shop-map'],
      ['eleme://web?url=foo'],
      ['ftp://h5.ele.me/'],
      ['//h5.ele.me/shop-map'],
    ])('rejects non-https / dangerous scheme %s and returns original link', (badUrl) => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: badUrl,
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });
  });

  describe('Security: H5 url host allow-list', () => {
    const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
    const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

    it('rejects off-allow-list hosts and returns original link', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://evil.example.com/phishing',
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });

    it('rejects host that only contains the suffix as a substring (look-alike)', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://ele.me.evil.com/phishing',
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });

    it('accepts the bare allow-list host (no subdomain)', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });

    it('accepts subdomains under the allow-list host', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });

    it('accepts custom allow-list overrides', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://my.internal.tools/page',
        disableShopAddressH5: 'false',
        allowedHostSuffixes: ['.internal.tools'],
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });
  });

  describe('Security / Correctness: requestParams keys win over otherParams (no clobber)', () => {
    it('does not duplicate eleStoreId when both requestParams and query carry it', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'FROM_REQUEST' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}&eleStoreId=FROM_QUERY`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      const u = new URL(decoded);
      // requestParams must win, query duplicate must be dropped
      expect(u.searchParams.getAll('eleStoreId')).toEqual(['FROM_REQUEST']);
    });
  });
});

