/**
 * Rewrites the legacy native "shop address landing page" jump link
 * (eleme://complexLayer?pageId=ShopInfo&...) into an H5 map page wrapped
 * by `eleme://web?url=...`.
 *
 * Falls back to the original link when:
 *   - the link is not a ShopInfo complexLayer schema
 *   - the H5 url template is empty / undefined
 *   - the rollback flag `disableShopAddressH5` is the literal string 'true'
 *   - the input cannot be parsed
 */

const SHOPINFO_PAGE_ID = 'ShopInfo';
const COMPLEX_LAYER_PREFIX = 'eleme://complexLayer';
const WEB_WRAPPER_PREFIX = 'eleme://web?url=';

/**
 * Default allow-list of host suffixes for the H5 map page.
 * Anything that does not match is rejected to defend against:
 *   - configuration-source poisoning (e.g. devtools / XSS write to
 *     `window.__downgradedConfiguration.shopAddressH5Url`)
 *   - dangerous URL schemes such as `javascript:`, `data:`, `file:`
 *   - open-redirect to phishing domains
 */
const DEFAULT_ALLOWED_HOST_SUFFIXES = ['.ele.me', '.alibaba-inc.com', '.taobao.com', '.tmall.com'];

export interface RewriteOptions {
  shopAddressH5Url?: string;
  disableShopAddressH5?: string | boolean;
  /** Override the default host allow-list. Pass an empty array to disable
   * the safety check (NOT recommended outside tests). */
  allowedHostSuffixes?: string[];
}

const isAllowedH5Url = (url: unknown, allowedSuffixes: string[]): url is string => {
  if (typeof url !== 'string' || url.length === 0) return false;
  // Must be HTTPS — blocks javascript:, data:, file:, http:, eleme:, etc.
  if (!url.startsWith('https://')) return false;
  // Empty allow-list disables the host check (test override only).
  if (allowedSuffixes.length === 0) return true;
  let host: string;
  try {
    host = new URL(url).hostname.toLowerCase();
  } catch {
    return false;
  }
  if (!host) return false;
  return allowedSuffixes.some(
    (suffix) => host === suffix.replace(/^\./, '') || host.endsWith(suffix.toLowerCase()),
  );
};

interface ParsedComplexLayer {
  pageId: string | null;
  requestParams: string | null;
  utParams: string | null;
  otherParams: Array<[string, string]>;
}

const isDisabled = (flag: string | boolean | undefined): boolean => flag === 'true' || flag === true;

const parseComplexLayer = (input: string): ParsedComplexLayer | null => {
  // We do not rely on `new URL` because `eleme://` is a non-standard scheme
  // and some runtimes (notably miniapp / weex) may parse it inconsistently.
  const queryStart = input.indexOf('?');
  if (queryStart < 0) return { pageId: null, requestParams: null, utParams: null, otherParams: [] };

  const search = input.slice(queryStart + 1);
  const pairs = search.split('&').filter(Boolean);
  let pageId: string | null = null;
  let requestParams: string | null = null;
  let utParams: string | null = null;
  const otherParams: Array<[string, string]> = [];

  for (const pair of pairs) {
    const eq = pair.indexOf('=');
    const key = eq < 0 ? pair : pair.slice(0, eq);
    const rawValue = eq < 0 ? '' : pair.slice(eq + 1);
    let value: string;
    try {
      value = decodeURIComponent(rawValue);
    } catch {
      value = rawValue;
    }
    if (key === 'pageId') {
      pageId = value;
    } else if (key === 'requestParams') {
      requestParams = value;
    } else if (key === 'utParams') {
      utParams = value;
    } else {
      otherParams.push([key, value]);
    }
  }
  return { pageId, requestParams, utParams, otherParams };
};

const safeParseRequestParams = (raw: string | null): Record<string, unknown> | null => {
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object') return parsed as Record<string, unknown>;
    return null;
  } catch {
    return null;
  }
};

const appendQuery = (url: string, key: string, value: string): string => {
  const sep = url.includes('?') ? '&' : '?';
  return `${url}${sep}${encodeURIComponent(key)}=${encodeURIComponent(value)}`;
};

export const rewriteShopAddressJumpLink = (
  jumpLink: string | null | undefined,
  options: RewriteOptions = {},
): string => {
  // Defensive: empty / nullish inputs are returned as the empty string so that
  // downstream callers can still pass the value into navigate() without throwing.
  if (!jumpLink || typeof jumpLink !== 'string') return '';

  const { shopAddressH5Url, disableShopAddressH5 } = options;
  const allowedSuffixes = options.allowedHostSuffixes ?? DEFAULT_ALLOWED_HOST_SUFFIXES;

  // Rollback / no-op fast paths.
  if (isDisabled(disableShopAddressH5)) return jumpLink;
  // Reject empty / non-string / non-HTTPS / off-allow-list H5 templates.
  // This is the primary defense against configuration-source poisoning
  // (see DEFAULT_ALLOWED_HOST_SUFFIXES).
  if (!isAllowedH5Url(shopAddressH5Url, allowedSuffixes)) return jumpLink;
  if (!jumpLink.startsWith(COMPLEX_LAYER_PREFIX)) return jumpLink;

  let parsed: ParsedComplexLayer | null;
  try {
    parsed = parseComplexLayer(jumpLink);
  } catch {
    return jumpLink;
  }
  if (!parsed) return jumpLink;
  if (parsed.pageId !== SHOPINFO_PAGE_ID) return jumpLink;

  // Build the H5 url, preserving the template's own query (if any).
  // Track keys we have already written so the explicit
  // `requestParams` / `utParams` always win over arbitrary `otherParams`
  // (matches the behavior promised by the inline comment below).
  let h5Url = shopAddressH5Url;
  const writtenKeys = new Set<string>();
  const writeOnce = (key: string, value: string) => {
    if (writtenKeys.has(key)) return;
    writtenKeys.add(key);
    h5Url = appendQuery(h5Url, key, value);
  };

  const requestObj = safeParseRequestParams(parsed.requestParams);
  if (requestObj) {
    for (const [k, v] of Object.entries(requestObj)) {
      if (v === undefined || v === null) continue;
      writeOnce(k, String(v));
    }
  }
  if (parsed.utParams) {
    writeOnce('utParams', parsed.utParams);
  }
  for (const [k, v] of parsed.otherParams) {
    // Skip if requestParams / utParams already wrote this key — they win.
    writeOnce(k, v);
  }

  return `${WEB_WRAPPER_PREFIX}${encodeURIComponent(h5Url)}`;
};

export default rewriteShopAddressJumpLink;

