import { renderHook, act } from '@testing-library/react-hooks';
import { useShopAddressNavigate } from '../useShopAddressNavigate';

// $ele() is a global declared in typings.d.ts; in tests we replace it.
const mockNavigate = jest.fn();

beforeAll(() => {
  // @ts-expect-error injecting test global
  global.$ele = jest.fn(() => ({ navigate: mockNavigate }));
});

beforeEach(() => {
  mockNavigate.mockReset();
  // Reset downgraded configuration to a clean slate per test.
  delete (window as any).__downgradedConfiguration;
});

const setConfig = (cfg: Record<string, unknown>) => {
  (window as any).__downgradedConfiguration = cfg;
};

describe('useShopAddressNavigate', () => {
  describe('AC1: rewrites and navigates when H5 url is configured and link is ShopInfo', () => {
    it('calls $ele().navigate exactly once with the eleme://web url', () => {
      setConfig({
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledTimes(1);
      const called = mockNavigate.mock.calls[0][0] as { url: string };
      expect(called.url.startsWith('eleme://web?url=')).toBe(true);
    });
  });

  describe('AC2: passes original link through when H5 url is missing', () => {
    it('calls navigate with the unchanged link', () => {
      // No __downgradedConfiguration at all.
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledTimes(1);
      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC3: passes through non-ShopInfo links untouched', () => {
    it('does not rewrite lmagex schema even when H5 url is configured', () => {
      setConfig({ shopAddressH5Url: 'https://h5.ele.me/shop-map' });
      const link = 'eleme://lmagex?scene_name=foo';

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC4: rollback flag forces fallback to original link', () => {
    it('does not rewrite when disableShopAddressH5=true even if H5 url is configured', () => {
      setConfig({
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'true',
      });
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
      const link = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });

  describe('AC bonus: empty / nullish input does not crash and does not call navigate', () => {
    it('skips navigate for empty string', () => {
      setConfig({ shopAddressH5Url: 'https://h5.ele.me/shop-map' });

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress('');
      });

      expect(mockNavigate).not.toHaveBeenCalled();
    });
  });

  describe('Security: ignores non-string config values', () => {
    it('treats numeric shopAddressH5Url as missing (falls back to original)', () => {
      setConfig({ shopAddressH5Url: 12345 });
      const link = 'eleme://complexLayer?pageId=ShopInfo&requestParams=%7B%7D';

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });

    it('rejects javascript: scheme even if config is set to it', () => {
      setConfig({ shopAddressH5Url: 'javascript:alert(1)' });
      const link = 'eleme://complexLayer?pageId=ShopInfo&requestParams=%7B%7D';

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });

    it('rejects off-allow-list https domain (open-redirect defense)', () => {
      setConfig({ shopAddressH5Url: 'https://evil.example.com/page' });
      const link = 'eleme://complexLayer?pageId=ShopInfo&requestParams=%7B%7D';

      const { result } = renderHook(() => useShopAddressNavigate());
      act(() => {
        result.current.navigateToShopAddress(link);
      });

      expect(mockNavigate).toHaveBeenCalledWith({ url: link });
    });
  });
});

