import { useCallback } from 'react';
import { rewriteShopAddressJumpLink } from '@/common/utils/shopAddressJumpLink';

/**
 * Hook that wraps `$ele().navigate({ url })` with the shop-address jump-link
 * rewrite logic. Components that previously called `$ele().navigate({ url: jumpLink })`
 * directly to open the legacy `eleme://complexLayer?pageId=ShopInfo&...` page
 * should switch to `navigateToShopAddress(jumpLink)` so that we can route the
 * user to the new H5 map page when configured.
 *
 * Reads two fields from `window.__downgradedConfiguration`:
 *   - shopAddressH5Url:        H5 map page URL template (no rewrite when empty)
 *   - disableShopAddressH5:    'true' for one-click rollback
 */
export const useShopAddressNavigate = () => {
  // Empty deps array is intentional: the configuration is read at *call*
  // time inside the callback, not at render time, so the closure cannot
  // become stale. Do NOT lift the config read above this line, or you
  // will miss runtime updates of `__downgradedConfiguration`.
  const navigateToShopAddress = useCallback((jumpLink: string | null | undefined) => {
    if (!jumpLink) return;

    const config = (typeof window !== 'undefined'
      ? (window as Window & {
          __downgradedConfiguration?: {
            shopAddressH5Url?: string;
            disableShopAddressH5?: string;
            [key: string]: unknown;
          };
        }).__downgradedConfiguration
      : undefined) ?? {};

    // Runtime-typed extraction: configuration is global writable state, so
    // even though TypeScript believes the fields are strings we still verify
    // at runtime to defend against numbers / objects / null injected by
    // unrelated code paths.
    const rawH5Url = config.shopAddressH5Url;
    const shopAddressH5Url = typeof rawH5Url === 'string' ? rawH5Url : undefined;
    const rawDisable = config.disableShopAddressH5;
    const disableShopAddressH5 =
      typeof rawDisable === 'string' || typeof rawDisable === 'boolean' ? rawDisable : undefined;

    const finalUrl = rewriteShopAddressJumpLink(jumpLink, {
      shopAddressH5Url,
      disableShopAddressH5,
    });

    try {
      $ele().navigate({ url: finalUrl });
    } catch (err) {
      // Fallback: if rewrite produced something the navigator dislikes, retry
      // with the raw link so the user is never stranded.
      // eslint-disable-next-line no-console
      console.error('[useShopAddressNavigate] navigate failed, falling back to raw link', err);
      try {
        $ele().navigate({ url: jumpLink });
      } catch (innerErr) {
        // eslint-disable-next-line no-console
        console.error('[useShopAddressNavigate] fallback navigate also failed', innerErr);
      }
    }
  }, []);

  return { navigateToShopAddress };
};

export default useShopAddressNavigate;

