26	export const useStoreStory = ({ storeId, itemBizCode }: UseStoreStoryProps) => {
27	  const [showPopup, setShowPopup] = useState(false);
28	  const [loading, setLoading] = useState(false);
29	  const [storyData, setStoryData] = useState<StoreStoryData | null>(null);
30	
31	  // 获取商家故事详情的接口调用
32	  const fetchStoreStoryDetail = useCallback(async () => {
33	    if (!storeId) {
34	      $ele().utils.Toast.show({
35	        content: '店铺信息获取失败',
36	        duration: 1500,
37	        position: 'center',
38	        maskClickable: true,
39	      });
40	      return;
41	    }
42	
43	    setLoading(true);
44	
45	    try {
46	      const params = {
47	        scene: 'wm_shopinfo',
48	        storeId,
49	        eleStoreId: storeId,
50	        itemBizCode: itemBizCode,
51	      };
52	
53	
54	      const result = await $ele().utils.mtopRequest({
55	        api: 'mtop.alsc.wamai.store.detail.miniapp.business.layer',
56	        data: params,
57	        v: '1.0',
58	        dataType: 'json',
59	        ecode: 0,
60	        type: 'GET',
61	      });
62	
63	
64	      setStoryData(result);
65	    } catch (error) {
66	      console.error('调试：获取商家故事详情失败', error);
67	      $ele().utils.Toast.show({
68	        content: '获取商家信息失败，请稍后重试',
69	        duration: 1500,
70	        position: 'center',
71	        maskClickable: true,
72	      });
73	    } finally {
74	      setLoading(false);
75	    }
76	  }, [storeId]);
77	
78	  // 打开弹窗并获取数据
79	  const openStoryPopup = useCallback(async () => {
80	    setShowPopup(true);
81	    await fetchStoreStoryDetail();
82	  }, [fetchStoreStoryDetail]);
83	
84	  // 关闭弹窗
85	  const closeStoryPopup = useCallback(() => {
86	    setShowPopup(false);
87	    setStoryData(null);
88	  }, []);
89	
90	  return {
91	    showPopup,
92	    loading,
93	    storyData,
94	    openStoryPopup,
95	    closeStoryPopup,
96	  };
97	};

