103	        const text = await getBoundingClientRectAsync(name);
104	        const textWidth = text?.width || 0;
105	
106	        if (containerWidth < textWidth) {
107	          setShowMask(true);
108	        }
109	      } catch (error) {}
110	    };
111	    if (storeInfo?.name?.length > 0 && scrollRef.current && nameRef.current) {
