136	    if (textTagUserTrack?.control_name && textTagUserTrack?.spm_c) {
137	      try {
138	        $ele().ltracker.click(`${textTagUserTrack.spm_c}.${textTagUserTrack.spm_d ?? '1'}`, {
139	          ...(textTagUserTrack.bizParams ?? {}),
140	        });
