146	
147	  // 可堂食标签曝光埋点
148	  useEffect(() => {
149	    if (showTextTag && textTagUserTrack && !hasExposedTextTagRef.current) {
150	      if (textTagUserTrack.exposure_name && textTagUserTrack.spm_c) {
151	        try {
152	          $ele().ltracker.expo(`${textTagUserTrack.spm_c}.${textTagUserTrack.spm_d ?? '1'}`, {
153	            ...(textTagUserTrack.bizParams ?? {}),
