182	            }
183	            onClick={handleTitleClick}
184	            style={{
185	              width: rpxToPxV2(wideLogoWidth),
186	              height: rpxToPxV2(wideLogoHeight),
187	              backgroundColor: isSkeleton ? '#F3F6F8' : 'transparent',
188	              marginRight: rpxToPxV2(8),
