export const rewriteShopAddressJumpLink = (
  jumpLink: string | null | undefined,
  options: RewriteOptions = {},
): string => {
  // Defensive: empty / nullish inputs are returned as the empty string so that
  // downstream callers can still pass the value into navigate() without throwing.
  if (!jumpLink || typeof jumpLink !== 'string') return '';

  const { shopAddressH5Url, disableShopAddressH5 } = options;

  // Rollback / no-op fast paths.
  if (isDisabled(disableShopAddressH5)) return jumpLink;
  if (!shopAddressH5Url) return jumpLink;
  if (!jumpLink.startsWith(COMPLEX_LAYER_PREFIX)) return jumpLink;

  let parsed: ParsedComplexLayer | null;
  try {
    parsed = parseComplexLayer(jumpLink);
  } catch {
    return jumpLink;
  }
  if (!parsed) return jumpLink;
  if (parsed.pageId !== SHOPINFO_PAGE_ID) return jumpLink;

  // Build the H5 url, preserving the template's own query (if any).
  let h5Url = shopAddressH5Url;
  const requestObj = safeParseRequestParams(parsed.requestParams);
  if (requestObj) {
    for (const [k, v] of Object.entries(requestObj)) {
      if (v === undefined || v === null) continue;
      h5Url = appendQuery(h5Url, k, String(v));
    }
  }
  if (parsed.utParams) {
    h5Url = appendQuery(h5Url, 'utParams', parsed.utParams);
  }
  for (const [k, v] of parsed.otherParams) {
    // Avoid clobbering query keys we already wrote (eleStoreId etc.) — they win.
    h5Url = appendQuery(h5Url, k, v);
  }

  return `${WEB_WRAPPER_PREFIX}${encodeURIComponent(h5Url)}`;
};

