  // Track keys we have already written so the explicit
  // `requestParams` / `utParams` always win over arbitrary `otherParams`
  // (matches the behavior promised by the inline comment below).
  let h5Url = shopAddressH5Url;
  const writtenKeys = new Set<string>();
  const writeOnce = (key: string, value: string) => {
    if (writtenKeys.has(key)) return;
    writtenKeys.add(key);
    h5Url = appendQuery(h5Url, key, value);
  };

  const requestObj = safeParseRequestParams(parsed.requestParams);
