      if (v === undefined || v === null) continue;
      writeOnce(k, String(v));
    }
  }
  if (parsed.utParams) {
    writeOnce('utParams', parsed.utParams);
  }
  for (const [k, v] of parsed.otherParams) {
    // Skip if requestParams / utParams already wrote this key — they win.
    writeOnce(k, v);
  }

  return `${WEB_WRAPPER_PREFIX}${encodeURIComponent(h5Url)}`;
};

