      expect(decoded).toContain('from=tb');
      expect(decoded).toContain('eleStoreId=E1');
      // No double ? in the URL
      const u = new URL(decoded);
      expect(u.searchParams.get('from')).toBe('tb');
      expect(u.searchParams.get('eleStoreId')).toBe('E1');
    });
  });

  describe('Security: H5 url scheme allow-list', () => {
    const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
    const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

    it.each([
      ['javascript:alert(1)'],
      ['data:text/html,<script>1</script>'],
      ['file:///etc/passwd'],
      ['http://h5.ele.me/shop-map'],
      ['eleme://web?url=foo'],
      ['ftp://h5.ele.me/'],
      ['//h5.ele.me/shop-map'],
    ])('rejects non-https / dangerous scheme %s and returns original link', (badUrl) => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: badUrl,
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });
  });

  describe('Security: H5 url host allow-list', () => {
    const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'E1' }));
    const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}`;

    it('rejects off-allow-list hosts and returns original link', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://evil.example.com/phishing',
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });

    it('rejects host that only contains the suffix as a substring (look-alike)', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://ele.me.evil.com/phishing',
        disableShopAddressH5: 'false',
      });
      expect(out).toBe(input);
    });

    it('accepts the bare allow-list host (no subdomain)', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });

    it('accepts subdomains under the allow-list host', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });

    it('accepts custom allow-list overrides', () => {
      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://my.internal.tools/page',
        disableShopAddressH5: 'false',
        allowedHostSuffixes: ['.internal.tools'],
      });
      expect(out.startsWith('eleme://web?url=')).toBe(true);
    });
  });

  describe('Security / Correctness: requestParams keys win over otherParams (no clobber)', () => {
    it('does not duplicate eleStoreId when both requestParams and query carry it', () => {
      const requestParams = encodeURIComponent(JSON.stringify({ eleStoreId: 'FROM_REQUEST' }));
      const input = `eleme://complexLayer?pageId=ShopInfo&requestParams=${requestParams}&eleStoreId=FROM_QUERY`;

      const out = rewriteShopAddressJumpLink(input, {
        shopAddressH5Url: 'https://h5.ele.me/shop-map',
        disableShopAddressH5: 'false',
      });

      const decoded = decodeURIComponent(out.slice('eleme://web?url='.length));
      const u = new URL(decoded);
      // requestParams must win, query duplicate must be dropped
      expect(u.searchParams.getAll('eleStoreId')).toEqual(['FROM_REQUEST']);
    });
  });
});

